mapper.select:
SELECT DISTINCT p.*, u.uid, u.uname, u.path as user_path, u.verified as user_verified, COUNT(DISTINCT r.rid) as reply_count, COUNT(DISTINCT f2.fid) as favorite_count FROM post p INNER JOIN favorite f ON p.pid = f.pid LEFT JOIN user u ON p.uid = u.uid LEFT JOIN reply r ON p.pid = r.pid LEFT JOIN favorite f2 ON p.pid = f2.pid WHERE f.uid = #{uid}
AND p.category = #{category}
GROUP BY p.pid, u.uid, u.uname, u.path, u.verified ORDER BY CASE WHEN p.is_sticky = 1 THEN 0 ELSE 1 END, p.lastreplytime DESC LIMIT #{startPage}, 4

SELECT COUNT(DISTINCT p.pid)
FROM post p
INNER JOIN favorite f ON p.pid = f.pid
WHERE f.uid = #{uid}

    AND p.category = #{category}
